<template>
    <transition name="fade" >
        <section class="app-container" v-if="!isLoading" key="is-loading-success">
            <header class="app-header">
                <app-header></app-header>
            </header>
            <main class="app-body" >
                <transition name="fade" mode="out-in" >
                    <router-view />
                </transition>
            </main>
            <footer class="app-footer">
                <app-footer></app-footer>
            </footer>
            <app-quick-view></app-quick-view>
        </section>
        <section v-else key="is-loading" class="app-container-loading">
            <div class="icon-loading bg-warning large"></div>
        </section>
    </transition>
</template>


<script>
    import  AppHeader from './partials/header'
    import  AppFooter from './partials/footer'
    import  AppQuickView from '@/components/quick-view'
    export default {
        name: 'defaultLayout',
        components : {
            AppHeader , AppFooter , AppQuickView 
        },
        metaInfo: {
            title: 'DropSquare',
            titleTemplate: '%s - DropSquare is Online Shopping for DropShopping.',
            meta: [
                {
                    'http-equiv': 'Content-Type',
                    'content': 'text/html; charset=utf-8'
                },
                {
                    'http-equiv': 'content-language' ,
                    'content' : 'en'
                },
                {
                    'name': 'viewport',
                    'content': 'width=device-width, initial-scale=1, maximum-scale=1, user-scalable=no'
                },
                {
                    'name' : 'robots',
                    'content' : 'follow,noindex'
                },
                {
                    'name': 'description',
                    'vmid': 'description',
                    'content': 'Online Shopping for DropShopping.'
                },
                {
                    'name' : 'og:type',
                    'vmid' : 'og:type',
                    'property' : 'og:type',
                    'content' : 'website'
                },
                {
                    'name' : 'og:url',
                    'vmid' : 'og:url',
                    'property' : 'og:url',
                    'content' : 'https://dropsquare.com'
                },
                {
                    'name' : 'og:title',
                    'vmid' : 'og:title',
                    'property' : 'og:title',
                    'content' : 'DropSquare is Online Shopping for DropShopping.'
                },
                {
                    'name' : 'og:description',
                    'vmid' : 'og:description',
                    'property' : 'og:description',
                    'content' : 'DropSquare is Online Shopping for DropShopping.'
                },
                {
                    'name' : 'og:image',
                    'vmid' : 'og:image',
                    'property' : 'og:image',
                    'content' : 'https://'
                },
                {
                    'name' : 'og:site_name',
                    'property' : 'og:site_name',
                    'content' : 'DropSquare is Online Shopping for DropShopping.'
                },
            ]
        },
        data(){
            return {
               isLoading : true,
            }
        },
        created : async function(){
            this.isLoading = true
            try {
                await this.$store.dispatch('$_Home/GET_LIST_COLLECTIONS', {})
            } catch (e) {}
            try {
                await this.$store.dispatch('$_Home/GET_LIST_COUNTRIES', {})
            } catch (e) {}
            
            try {
                await this.$store.dispatch('$_Home/GET_LIST_SUPPLIERS', {})
            } catch (e) {}
            var isLogin = this.$store.getters['$_Seller/isLoggedIn']
            if( isLogin  ){
                // await this.$store.dispatch('$_Seller/GET_USER_INFO', {})
            }
            this.isLoading = false
        },
        mounted(){
            
       }

    }
</script>

<style lang="scss" >
    @import 'src/assets/scss/static/variables';
    .app-container{
        display: flex;
        flex-direction: column ;
        height: 100vh;
        min-width: 1140px;
        &-loading{
            height: 100vh;
            width: 100vw;
            display: flex;
            justify-content: center;
            align-items: center;
        }
        .app-header{
            width: 100%;
        }
        .app-footer{
            width: 100%;
        }
        .app-body{
            flex: auto;
            width: 100%;
            
        }
    }
